// Определяем что пришло: уже извлечённый текст (от браузера) или бинарный файл.
// n8n webhook кладёт JSON-body в $json.body, а form-data поля в корень.
// Поэтому ищем text и в .body, и в корне для надёжности.

const item = $input.first();
const root = item.json || {};
const body = (root.body && typeof root.body === 'object') ? root.body : {};
const binary = item.binary || {};
const binaryKeys = Object.keys(binary);

function pick(field) {
  if (typeof body[field] === 'string' && body[field].length > 0) return body[field];
  if (typeof root[field] === 'string' && root[field].length > 0) return root[field];
  return null;
}

const text = pick('text');
const fileName = pick('fileName') || 'document.txt';
const source = pick('source') || 'browser';

// Браузерный путь: JSON с готовым текстом
if (text && text.trim().length > 0) {
  return [{
    json: {
      has_text: true,
      text: text,
      fileName: fileName,
      source: source
    }
  }];
}

// Файловый путь: есть binary
if (binaryKeys.length > 0) {
  const key = binaryKeys[0];
  const info = binary[key];
  const realFileName = info.fileName || 'unknown';
  const fileSize = info.fileSize || 0;

  if (fileSize > 50 * 1024 * 1024) {
    return [{ json: { has_text: false, has_file: false, error: 'Файл слишком большой (макс. 50 МБ).' } }];
  }

  return [{
    json: {
      has_text: false,
      has_file: true,
      binaryKey: key,
      fileName: realFileName,
      mimeType: info.mimeType || 'unknown'
    },
    binary: binary
  }];
}

// Ничего не пришло — лог что было в root для отладки
const rootKeys = Object.keys(root).slice(0, 10).join(',');
return [{ json: { has_text: false, has_file: false, error: 'Файл не загружен и текст не передан. (Получено: root=[' + rootKeys + '])' } }];

// Извлекаем текст из ответа OCR (только если файл проходил через OCR ветку).
try {
  const data = $input.first().json;

  if (data.error) {
    const msg = typeof data.error === 'string' ? data.error : (data.error.message || JSON.stringify(data.error));
    return [{ json: { has_text: false, error: 'OCR ошибка: ' + msg } }];
  }

  let text = '';
  if (typeof data === 'string') text = data;
  else if (data.text && typeof data.text === 'string') text = data.text;
  else if (data.result && typeof data.result === 'string') text = data.result;
  else if (data.result && data.result.text) text = data.result.text;
  else if (data.content && typeof data.content === 'string') text = data.content;
  else if (data.data && typeof data.data === 'string') text = data.data;
  else if (data.output && typeof data.output === 'string') text = data.output;
  else text = JSON.stringify(data);

  text = text.trim();

  if (!text || text === '{}' || text === '[]' || text === 'null' || text.length < 3) {
    return [{ json: { has_text: false, error: 'OCR не смог распознать текст. Попробуйте другой файл.' } }];
  }

  // fileName тянем из «Определить вход»
  const fileName = $('Определить вход').first().json.fileName || 'unknown';
  return [{ json: { has_text: true, text: text, fileName: fileName, source: 'ocr' } }];
} catch (e) {
  return [{ json: { has_text: false, error: 'Ошибка обработки OCR: ' + e.message } }];
}

// Нарезаем текст на куски, сохраняя семантические границы абзацев.
//
// Старая версия делала split(/\s+/) и теряла всё форматирование —
// заголовки, абзацы сливались в один поток слов, эмбеддинги получались
// размытыми, RAG-поиск промахивался.
//
// Новая логика:
// 1) Бьём по двойным переносам (абзацы) или одиночным (если их нет).
// 2) Аккумулируем абзацы в чанк до лимита CHUNK_WORDS.
// 3) Если один абзац больше CHUNK_WORDS — разбиваем его на слова (старая логика).
// 4) Перекрытие OVERLAP — последние N слов из предыдущего чанка добавляем в начало следующего.

const text = $json.text;
const fileName = $json.fileName;
const source = $json.source || 'unknown';

const CHUNK_WORDS = 500;
const OVERLAP = 50;

const raw = String(text || '');
if (!raw.trim()) {
  return [{ json: { error: 'Текст пустой после обработки.' } }];
}

// 1) Разбиваем на параграфы. Если двойных переносов нет — на одинарные.
let paragraphs = raw.split(/\n\n+/).map(p => p.trim()).filter(p => p.length > 0);
if (paragraphs.length <= 1) {
  paragraphs = raw.split(/\n/).map(p => p.trim()).filter(p => p.length > 0);
}
if (paragraphs.length === 0) {
  paragraphs = [raw];
}

function wordCount(s) { return s.split(/\s+/).filter(w => w.length > 0).length; }

const chunks = [];
let buffer = [];
let bufferWords = 0;

function flushBuffer() {
  if (buffer.length === 0) return;
  const text = buffer.join('\n\n');
  chunks.push({
    json: {
      fileName: fileName,
      chunk_index: chunks.length,
      chunk_text: text,
      total_chunks: 0,
      source: source
    }
  });
  // Перекрытие: оставляем хвост последнего абзаца (OVERLAP слов)
  const lastWords = text.split(/\s+/).filter(w => w.length > 0);
  const tail = lastWords.slice(-OVERLAP).join(' ');
  buffer = tail ? [tail] : [];
  bufferWords = tail ? OVERLAP : 0;
}

for (const p of paragraphs) {
  const pw = wordCount(p);
  if (pw === 0) continue;

  // Большой абзац — режем его внутри по словам
  if (pw > CHUNK_WORDS) {
    if (buffer.length > 0) flushBuffer();
    const words = p.split(/\s+/).filter(w => w.length > 0);
    let start = 0;
    while (start < words.length) {
      const end = Math.min(start + CHUNK_WORDS, words.length);
      chunks.push({
        json: {
          fileName: fileName,
          chunk_index: chunks.length,
          chunk_text: words.slice(start, end).join(' '),
          total_chunks: 0,
          source: source
        }
      });
      if (end >= words.length) break;
      start += CHUNK_WORDS - OVERLAP;
    }
    continue;
  }

  // Обычный абзац — вместился бы в текущий буфер?
  if (bufferWords + pw > CHUNK_WORDS && buffer.length > 0) {
    flushBuffer();
  }
  buffer.push(p);
  bufferWords += pw;
}

flushBuffer();

if (chunks.length === 0) {
  return [{ json: { error: 'Текст пустой после обработки.' } }];
}

for (const c of chunks) c.json.total_chunks = chunks.length;
return chunks;

// Извлекаем вектор из ответа эмбеддинга. Параметры для INSERT кладём как
// есть — Postgres-нода ниже использует queryReplacement (параметризация),
// поэтому здесь НЕ нужно делать ручной escape кавычек или склейку SQL.
try {
  const data = $input.first().json;
  const prevData = $('Нарезка на куски').first().json;
  const fileName = prevData.fileName;
  const chunkIndex = prevData.chunk_index;
  const chunkText = prevData.chunk_text;
  const totalChunks = prevData.total_chunks;

  if (data.error) {
    return [{ json: { success: false, error: 'Ошибка эмбеддинга: ' + JSON.stringify(data.error) } }];
  }

  let vector = null;
  if (data.data && Array.isArray(data.data) && data.data[0] && data.data[0].embedding) {
    vector = data.data[0].embedding;
  } else if (data.embedding && Array.isArray(data.embedding)) {
    vector = data.embedding;
  } else if (Array.isArray(data) && data.length > 0 && typeof data[0] === 'number') {
    vector = data;
  }

  if (!vector || vector.length === 0) {
    return [{ json: { success: false, error: 'Эмбеддинг вернул пустой вектор.' } }];
  }

  // Defense-in-depth: убеждаемся что вектор — это массив конечных чисел.
  if (!vector.every(v => typeof v === 'number' && Number.isFinite(v))) {
    return [{ json: { success: false, error: 'Невалидный вектор от эмбеддера (не числа).' } }];
  }

  // pgvector принимает строку вида '[1.0,2.0,...]'. Передаём как параметр.
  const vectorStr = '[' + vector.join(',') + ']';

  return [{ json: {
    success: true,
    fileName: fileName,
    chunk_index: chunkIndex,
    chunk_text: chunkText,
    vector_str: vectorStr,
    total_chunks: totalChunks,
    vector_size: vector.length
  }}];
} catch (e) {
  return [{ json: { success: false, error: 'Ошибка обработки эмбеддинга: ' + e.message } }];
}

// Агрегируем результаты записи всех кусков.
// Сообщение для пользователя — короткое и без технических деталей
// (OCR/browser, число кусков, доступно для поиска и т.д.).
// Все технические поля — в data.details для логов и админки.
function errToString(e) {
  if (!e) return '';
  if (typeof e === 'string') return e;
  if (typeof e === 'object') {
    if (e.message) return String(e.message);
    if (e.detail) return String(e.detail);
    try { return JSON.stringify(e); } catch (_) { return String(e); }
  }
  return String(e);
}

const items = $input.all();
let success = 0;
let failed = 0;
let errors = [];
let fileName = '';
let totalChunks = 0;
let source = '';

for (const item of items) {
  const prev = item.json || {};
  if (!fileName && prev.fileName) fileName = prev.fileName;
  if (!totalChunks && prev.total_chunks) totalChunks = prev.total_chunks;
  if (!source && prev.source) source = prev.source;
  if (prev.error) {
    failed++;
    errors.push(errToString(prev.error));
  } else {
    success++;
  }
}

if (success === 0 && failed === 0) {
  success = items.length;
}

if (!fileName) {
  try { fileName = $('Нарезка на куски').first().json.fileName; } catch (_) {}
}
if (!source) {
  try { source = $('Нарезка на куски').first().json.source; } catch (_) {}
}

let message = '';
if (failed === 0) {
  message = 'Документ загружен';
} else if (success > 0) {
  // Частичный успех — единственный case когда юзеру нужно знать о проблеме.
  message = 'Документ загружен с замечаниями. Часть фрагментов не удалось сохранить — попробуйте загрузить ещё раз.';
} else {
  const uniqErrors = Array.from(new Set(errors)).slice(0, 1);
  message = 'Не удалось загрузить документ' + (uniqErrors[0] ? ': ' + uniqErrors[0] : '.');
}

return [{ json: {
  response: message,
  ok: failed === 0,
  // Тех. детали — только для админки/логов, фронт их не показывает
  details: { fileName: fileName, success: success, failed: failed, source: source }
} }];

// === SSO Phase 3: token presence check ===
// Token может быть в body (JSON request) ИЛИ form-data (file upload).
// Для form-data n8n кладёт поля в корень $json (не в .body).
const item = $input.first();
const j = item && item.json ? item.json : {};
const body = j.body || j;
const token = String((body && body.token) || j.token || '').trim();
if (!token) {
  return [{ json: { __auth_required: true } }];
}
// Прокидываем все исходные поля + binary data дальше (binary не теряется
// автоматически при возврате json — n8n сохраняет binary поле item.binary
// если мы возвращаем СОДЕРЖИМОЕ $json, но не если возвращаем новый объект.
// Используем item.binary в выходе явно.
return [{ json: { ...j, token: token, __auth_ok: true }, binary: item.binary || {} }];

